    11→
    12→// ProjectsStore defines the persistence operations for projects.
    13→type ProjectsStore interface {
    14→	ListProjects(ctx context.Context, page, perPage int) ([]models.Project, int, error)
    15→	CreateProject(ctx context.Context, p *models.Project) error
    16→	GetProject(ctx context.Context, id string) (*models.Project, error)
    17→	UpdateProject(ctx context.Context, id string, p *models.Project) error
    18→	DeleteProject(ctx context.Context, id string) error
    19→}
    20→
    21→// ProjectsHandler implements HTTP handlers for the /projects resource.
    22→type ProjectsHandler struct {
    23→	store ProjectsStore
    24→}
    25→
    26→// NewProjectsHandler returns a new ProjectsHandler.
    27→func NewProjectsHandler(store ProjectsStore) *ProjectsHandler {
    28→	return &ProjectsHandler{store: store}
    29→}
    30→
    31→// List handles GET /projects — returns a paginated list of projects.
    32→func (h *ProjectsHandler) List(w http.ResponseWriter, r *http.Request) {
    33→	page, perPage := ParsePagination(r)
    34→	projects, total, err := h.store.ListProjects(r.Context(), page, perPage)
    35→	if err != nil {
    36→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to list projects")
    37→		return
    38→	}
    39→	// Return empty array, not null, when no results.
    40→	if projects == nil {
    41→		projects = []models.Project{}
    42→	}
    43→	RespondList(w, r, http.StatusOK, projects, page, perPage, total)
    44→}
    45→
    46→// Create handles POST /projects — creates a new project.
    47→func (h *ProjectsHandler) Create(w http.ResponseWriter, r *http.Request) {
    48→	var p models.Project
    49→	if err := DecodeJSON(r, &p); err != nil {
    50→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid JSON body")
    51→		return
    52→	}
    53→	p.Name = strings.TrimSpace(p.Name)
    54→	if p.Name == "" {
    55→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "Name is required")
    56→		return
    57→	}
    58→	// Default agent_rules to empty object if not provided.
    59→	if p.AgentRules == nil {
    60→		p.AgentRules = json.RawMessage(`{}`)
    61→	}
    62→	if err := h.store.CreateProject(r.Context(), &p); err != nil {
    63→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to create project")
    64→		return
    65→	}
    66→	RespondJSON(w, r, http.StatusCreated, p)
    67→}
    68→
    69→// Get handles GET /projects/{id} — returns a single project.
    70→func (h *ProjectsHandler) Get(w http.ResponseWriter, r *http.Request) {
    71→	id := r.PathValue("id")
    72→	if id == "" {
    73→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid project ID")
    74→		return
    75→	}
    76→	p, err := h.store.GetProject(r.Context(), id)
    77→	if err != nil {
    78→		RespondError(w, r, http.StatusNotFound, "not_found", "Project not found")
    79→		return
    80→	}
    81→	RespondJSON(w, r, http.StatusOK, p)
    82→}
    83→
    84→// Update handles PUT /projects/{id} — updates an existing project.
    85→func (h *ProjectsHandler) Update(w http.ResponseWriter, r *http.Request) {
    86→	id := r.PathValue("id")
    87→	if id == "" {
    88→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid project ID")
    89→		return
    90→	}
    91→	var p models.Project
    92→	if err := DecodeJSON(r, &p); err != nil {
    93→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid JSON body")
    94→		return
    95→	}
    96→	p.Name = strings.TrimSpace(p.Name)
    97→	if p.Name == "" {
    98→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "Name is required")
    99→		return
   100→	}
   101→	if p.AgentRules == nil {
   102→		p.AgentRules = json.RawMessage(`{}`)
   103→	}
   104→	if err := h.store.UpdateProject(r.Context(), id, &p); err != nil {
   105→		RespondError(w, r, http.StatusNotFound, "not_found", "Project not found")
   106→		return
   107→	}
   108→	p.ID = id
   109→	RespondJSON(w, r, http.StatusOK, p)
   110→}
   111→
   112→// Delete handles DELETE /projects/{id} — deletes a project.
   113→func (h *ProjectsHandler) Delete(w http.ResponseWriter, r *http.Request) {
   114→	id := r.PathValue("id")
   115→	if id == "" {
   116→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid project ID")
   117→		return
   118→	}
   119→	if err := h.store.DeleteProject(r.Context(), id); err != nil {
   120→		RespondError(w, r, http.StatusNotFound, "not_found", "Project not found")
   121→		return
   122→	}
   123→	w.WriteHeader(http.StatusNoContent)
   124→}
