    58→
    59→  const measure = useCallback(() => {
    60→    const el = measureRef.current;
    61→    if (!el) return;
    62→    const nodes = el.children;
    63→    const itemNodeCount = nodes.length - 2; // exclude label (first) and hidden "more…" span (last)
    64→    // Check if everything fits without overflow
    65→    if (el.scrollHeight <= MAX_HEIGHT + 4) {
    66→      setVisibleCount(items.length);
    67→      return;
    68→    }
    69→    // Measure actual "more…" link width
    70→    const moreWidth = moreRef.current ? moreRef.current.offsetWidth + 8 : 52;
    71→    const containerWidth = el.offsetWidth;
    72→    // First pass: find all items that fit within MAX_HEIGHT (2 lines)
    73→    let lastFitting = 0;
    74→    for (let i = 1; i <= itemNodeCount; i++) {
    75→      const node = nodes[i] as HTMLElement;
    76→      if (node.offsetTop + node.offsetHeight > MAX_HEIGHT) break;
    77→      lastFitting = i;
    78→    }
    79→    // Second pass: walk backward from lastFitting until "more…" fits after the item
    80→    let count = lastFitting;
    81→    while (count > 1) {
    82→      const node = nodes[count] as HTMLElement;
    83→      const nodeBottom = node.offsetTop + node.offsetHeight;
    84→      // If this item is on line 1, "more…" can always wrap to line 2 — we're fine
    85→      if (nodeBottom <= LINE_HEIGHT) break;
    86→      // Item is on line 2 — check if "more…" fits after it on the same line
    87→      const nodeRight = node.offsetLeft + node.offsetWidth;
    88→      if (nodeRight + moreWidth <= containerWidth) break;
    89→      count--;
    90→    }
    91→    setVisibleCount(Math.max(1, count));
    92→  }, [items.length]);
