package ingestion

import (
	"context"
	"log/slog"
	"time"

	"github.com/jackc/pgx/v5/pgxpool"
)

// Orchestrator runs polling ingestion sources on a fixed interval.
type Orchestrator struct {
	service       *Service
	loader        *SourceLoader
	pool          *pgxpool.Pool
	staticSources []IIngestionSource // for testing only
	interval      time.Duration
}

// NewOrchestrator creates an orchestrator that dynamically loads enabled
// sources from the database on each poll cycle.
func NewOrchestrator(service *Service, loader *SourceLoader, pool *pgxpool.Pool, interval time.Duration) *Orchestrator {
	return &Orchestrator{service: service, loader: loader, pool: pool, interval: interval}
}

// NewOrchestratorWithSources creates an orchestrator with a static source list.
// Intended for testing; production code should use NewOrchestrator with a SourceLoader.
func NewOrchestratorWithSources(service *Service, sources []IIngestionSource, interval time.Duration) *Orchestrator {
	return &Orchestrator{service: service, staticSources: sources, interval: interval}
}

// Run polls all sources immediately, then on every tick. Blocks until ctx is cancelled.
func (o *Orchestrator) Run(ctx context.Context) {
	ticker := time.NewTicker(o.interval)
	defer ticker.Stop()

	o.pollAll(ctx)

	for {
		select {
		case <-ctx.Done():
			return
		case <-ticker.C:
			o.pollAll(ctx)
		}
	}
}

func (o *Orchestrator) pollAll(ctx context.Context) {
	sources := o.staticSources
	if sources == nil {
		var err error
		sources, err = o.loader.LoadEnabledSources(ctx)
		if err != nil {
			slog.Error("load sources failed", "err", err)
			return
		}
	}
	if len(sources) == 0 {
		slog.Debug("no enabled sources to poll")
		return
	}
	for _, src := range sources {
		results, err := src.FetchNewReleases(ctx)
		if err != nil {
			slog.Error("poll failed", "source", src.Name(), "err", err)
			o.updateSourcePollStatus(ctx, src.SourceID(), err)
			continue
		}
		o.updateSourcePollStatus(ctx, src.SourceID(), nil)
		if len(results) == 0 {
			continue
		}
		if err := o.service.ProcessResults(ctx, src.SourceID(), src.Name(), results); err != nil {
			slog.Error("process failed", "source", src.Name(), "err", err)
		}
	}
}

func (o *Orchestrator) updateSourcePollStatus(ctx context.Context, sourceID string, pollErr error) {
	if o.pool == nil {
		return
	}
	var lastError *string
	if pollErr != nil {
		s := pollErr.Error()
		lastError = &s
	}
	_, err := o.pool.Exec(ctx,
		`UPDATE sources SET last_polled_at = NOW(), last_error = $1 WHERE id = $2`,
		lastError, sourceID)
	if err != nil {
		slog.Error("update source poll status", "source", sourceID, "err", err)
	}
}

package ingestion

import (
	"context"
	"fmt"
	"log/slog"
	"net/http"

	"github.com/jackc/pgx/v5/pgxpool"
)

// SourceLoader reads source configuration from the database and constructs
// IIngestionSource instances. It bridges the API-managed sources table with
// the polling orchestrator.
type SourceLoader struct {
	pool   *pgxpool.Pool
	client *http.Client
}

func NewSourceLoader(pool *pgxpool.Pool, client *http.Client) *SourceLoader {
	return &SourceLoader{pool: pool, client: client}
}

// LoadEnabledSources queries all enabled sources and constructs the
// appropriate IIngestionSource for each one based on provider.
func (l *SourceLoader) LoadEnabledSources(ctx context.Context) ([]IIngestionSource, error) {
	rows, err := l.pool.Query(ctx,
		`SELECT id, provider, repository FROM sources WHERE enabled = true`)
	if err != nil {
		return nil, fmt.Errorf("query enabled sources: %w", err)
	}
	defer rows.Close()

	var sources []IIngestionSource
	for rows.Next() {
		var id string
		var sourceType, repository string
		if err := rows.Scan(&id, &sourceType, &repository); err != nil {
			return nil, fmt.Errorf("scan source row: %w", err)
		}

		src := l.buildSource(id, sourceType, repository)
		if src == nil {
			slog.Warn("unsupported source type, skipping",
				"id", id, "type", sourceType, "repo", repository)
			continue
		}
		sources = append(sources, src)
	}
	return sources, rows.Err()
}

// LookupSourceID finds the source ID for a given (provider, repository) pair.
// Returns empty string and false if no matching enabled source exists.
func (l *SourceLoader) LookupSourceID(ctx context.Context, provider, repository string) (string, bool) {
	var id string
	err := l.pool.QueryRow(ctx,
		`SELECT id FROM sources WHERE provider = $1 AND repository = $2 AND enabled = true`,
		provider, repository,
	).Scan(&id)
	if err != nil {
		return "", false
	}
	return id, true
}

func (l *SourceLoader) buildSource(id string, sourceType, repository string) IIngestionSource {
	return BuildSource(l.client, id, sourceType, repository)
}

// BuildSource constructs the appropriate IIngestionSource based on provider type.
func BuildSource(client *http.Client, id string, sourceType, repository string) IIngestionSource {
	switch sourceType {
	case "dockerhub":
		return NewDockerHubSource(client, repository, id)
	case "github":
		return NewGitHubSource(client, repository, id)
	case "ecr-public":
		return NewECRPublicSource(client, repository, id)
	case "gitlab":
		return NewGitLabSource(client, repository, id)
	default:
		return nil
	}
}

